-inline int32_t getShuffleBlockSize(int epilogueTileM) {
-  int shuffleBlockSize = 16;
-  if (epilogueTileM % 128 == 0) {
-    shuffleBlockSize = 32;
-  }
-  return shuffleBlockSize;
-}
