-inline bool getDoesScaleC(tg::Dtype dtypeC) {
-  // Need to scale/quantize the output C matrix when the output type is Fp8 or NvFp4.
-  return dtypeC == tg::Dtype::E4m3 || dtypeC == tg::Dtype::E2m1;
