-  for (int32_t ii = 0; ii < dim; ++ii) {
-    assert(shapes[ii] >= (uint64_t(1)));        // Size must be min 1
-    assert(shapes[ii] <= (uint64_t(1) << 32));  // Size must be max 2^32
