-    cuGetErrorString(result, &errorString);
-    std::stringstream ss;
-    ss << "Error: Failed to initialize the TMA descriptor. " << errorString << std::endl;
-
-    ss << "tmaFormat: " << static_cast<int>(tmaDataFormat) << " dim: " << dim
