-
-// For logging and error reporting
-inline std::string dtypeToString(Dtype dtype) {
-  switch (dtype) {
-    case Dtype::Bfloat16:
-      return "Bfloat16";
-    case Dtype::Bool:
-      return "Bool";
-    case Dtype::E2m1:
-      return "E2m1";
-    case Dtype::E2m3:
-      return "E2m3";
-    case Dtype::E3m2:
-      return "E3m2";
-    case Dtype::E4m3:
-      return "E4m3";
-    case Dtype::E5m2:
-      return "E5m2";
-    case Dtype::Fp16:
-      return "Fp16";
-    case Dtype::Fp32:
-      return "Fp32";
-    case Dtype::Int8:
-      return "Int8";
-    case Dtype::Int32:
-      return "Int32";
-    case Dtype::Int64:
-      return "Int64";
-    case Dtype::MxE4m3:
-      return "MxE4m3";
-    case Dtype::MxE2m1:
-      return "MxE2m1";
-    case Dtype::MxInt4:
-      return "MxInt4";
-    case Dtype::UE8m0:
-      return "UE8m0";
-    case Dtype::UInt8:
-      return "UInt8";
-    case Dtype::UInt16:
-      return "UInt16";
-    case Dtype::UInt32:
-      return "UInt32";
-    case Dtype::UInt64:
-      return "UInt64";
-    case Dtype::UInt128:
-      return "UInt128";
-    case Dtype::Void:
-      return "Void";
-    default:
-      assert(false);
-      return "Unsupported type";
-  }
-}
-
-////////////////////////////////////////////////////////////////////////////////////////////////////
-
-inline Dtype dtypeEltType(Dtype dtype) {
-  switch (dtype) {
-    case Dtype::MxE2m1:
-      return Dtype::E2m1;
-    case Dtype::MxE4m3:
-      return Dtype::E4m3;
-    default:
-      return dtype;
-  }
-}
-
-////////////////////////////////////////////////////////////////////////////////////////////////////
-
-// Note: the block size from the options should be used instead.
-// TODO: remove this function?
-inline int dtypeNumEltsPerSf(Dtype dtype, bool useSparsity = false) {
-  switch (dtype) {
-    case Dtype::E2m1:
-      return useSparsity ? 32 : 16;
-    case Dtype::MxE2m1:
-    case Dtype::MxE4m3:
-    case Dtype::MxInt4:
-      return useSparsity ? 64 : 32;
-    default:
-      assert(false);
-      return -1;
-  }
-}
-
-////////////////////////////////////////////////////////////////////////////////////////////////////
-
-// Returns the dtype of scaling factors, if applicable.
-inline Dtype dtypeGetBlockSfType(Dtype dtype) {
-  switch (dtype) {
-    case Dtype::E2m1:
-      return Dtype::E4m3;
-    case Dtype::MxE2m1:
-    case Dtype::MxE4m3:
-      return Dtype::UE8m0;
-    case Dtype::MxInt4:
-      return Dtype::Bfloat16;
-    default:
-      assert(false);
-      return Dtype::Void;
-  }
-}
-
-////////////////////////////////////////////////////////////////////////////////////////////////////
-
-inline MmaKind dtypeGetMmaKind(Dtype dtypeA, Dtype dtypeB) {
-  auto dtypeEltA = dtypeEltType(dtypeA);
-  auto dtypeEltB = dtypeEltType(dtypeB);
-
-  // Note: the order of the conditions is important here.
-  if ((dtypeA == Dtype::Fp16 && dtypeB == Dtype::Fp16) ||
-      (dtypeA == Dtype::Bfloat16 && dtypeB == Dtype::Bfloat16)) {
-    return MmaKind::Fp16;
-  }
-
-  if ((dtypeA == Dtype::Int8 || dtypeA == Dtype::UInt8) &&
-      (dtypeB == Dtype::Int8 || dtypeB == Dtype::UInt8)) {
-    return MmaKind::Int8;
-  }
-
-  // This statement captures both MxE2m1 and E2m1.
-  if (dtypeEltA == Dtype::E2m1 && dtypeEltB == Dtype::E2m1) {
-    return MmaKind::MxFp4NvFp4;
-  }
-
-  if ((dtypeA == Dtype::E4m3 || dtypeA == Dtype::E5m2 || dtypeA == Dtype::E2m3 ||
-       dtypeA == Dtype::E3m2 || dtypeA == Dtype::E2m1) &&
-      (dtypeB == Dtype::E4m3 || dtypeB == Dtype::E5m2 || dtypeB == Dtype::E2m3 ||
-       dtypeB == Dtype::E3m2 || dtypeB == Dtype::E2m1)) {
-    return MmaKind::Fp8Fp6Fp4;
-  }
-
-  // At this point we know that both dtypes are Mx types and not both MxE2m1 at the same time.
-  if ((dtypeEltA == Dtype::E4m3 || dtypeEltA == Dtype::E5m2 || dtypeEltA == Dtype::E2m3 ||
-       dtypeEltA == Dtype::E3m2 || dtypeEltA == Dtype::E2m1) &&
-      (dtypeEltB == Dtype::E4m3 || dtypeEltB == Dtype::E5m2 || dtypeEltB == Dtype::E2m3 ||
-       dtypeEltB == Dtype::E3m2 || dtypeEltB == Dtype::E2m1)) {
-    return MmaKind::MxFp8Fp6Fp4;
-  }
-  return MmaKind::Tf32;
-}
-
-////////////////////////////////////////////////////////////////////////////////////////////////////
-
-inline bool dtypeNeedsPadding(Dtype dtype, MmaKind mmaKind, [[maybe_unused]] int mmaK,
-                              [[maybe_unused]] bool isSparseA) {
-  bool needsPadding = mmaKind == MmaKind::MxFp8Fp6Fp4 && dtype == Dtype::MxE2m1;
-  return needsPadding;
-}
